mapper.select:
SELECT tenant_id
FROM account_tenant_access
WHERE account_id = #{id}

mapper.update:
UPDATE account_tenant_access
SET account_id = #{accountId},
    tenant_id = #{tenantId}
WHERE id = #{id}

mapper.delete:
DELETE FROM account
WHERE id = #{id}
  AND status = #{status}

DELETE FROM account_tenant_access
WHERE id = #{id}
  AND tenant_id = #{tenantId}
